  // =========================================================================
  // concat_1
  // =========================================================================
  test("concat_1".fail) {
    assertCompresses(
      input = """var a = "foo" + "bar" + x() + "moo" + "foo" + y() + "x" + "y" + "z" + q();
        var b = "foo" + 1 + x() + 2 + "boo";
        var c = 1 + x() + 2 + "boo";

        // this CAN'T safely be shortened to 1 + x() + "5boo"
        var d = 1 + x() + 2 + 3 + "boo";

        var e = 1 + x() + 2 + "X" + 3 + "boo";

        // be careful with concatenation with "\0" with octal-looking strings.
        var f = "\0" + 360 + "\0" + 8 + "\0"""".stripMargin.trim,
      expected = """var a = "foobar" + x() + "moofoo" + y() + "xyz" + q();
        var b = "foo1" + x() + "2boo";
        var c = 1 + x() + 2 + "boo";
        var d = 1 + x() + 2 + 3 + "boo";
        var e = 1 + x() + 2 + "X3boo";
        var f = "\x00360\x008\0"""".stripMargin.trim,
      options = AllOff.copy(
        evaluate = true
      )
    )
  }

  // =========================================================================
  // concat_2
